struct CountDown {
    n: u32,
}

impl Iterator for CountDown {
    type Item = u32;

    fn next(&mut self) -> Option<u32> {
        if self.n == 0 { return None; }
        self.n -= 1;
        Some(self.n + 1)
    }

    fn size_hint(&self) -> (usize, Option<usize>) {
        // We know EXACTLY how many items remain: self.n
        let remaining = self.n as usize;
        (remaining, Some(remaining))
        // This enables ExactSizeIterator below
    }
}

// With exact knowledge, also implement ExactSizeIterator
impl ExactSizeIterator for CountDown {
    fn len(&self) -> usize {
        self.n as usize
    }
}

fn main() {
    let cd = CountDown { n: 10 };
    println!("len before collecting: {}", cd.len());

    let v: Vec<u32> = CountDown { n: 10 }.collect();
    println!("{:?}", v);
    // collect() pre-allocates exactly 10 slots — zero reallocations
}

