struct Splitter<'a> { s: &'a str }
impl<'a> Iterator for Splitter<'a> {
    type Item = &'a str;
    fn next(&mut self) -> Option<Self::Item> {
        if self.s.is_empty() { return None; }
        // Find the first character boundary to avoid panics on Unicode.
        let mut chars = self.s.chars();
        let _ = chars.next();
        let split_index = self.s.len() - chars.as_str().len();
        let (res, rest) = self.s.split_at(split_index);
        self.s = rest;
        Some(res)
    }
}

